"""User model for the API.

WARNING: Do NOT modify this file.
"""
from dataclasses import dataclass, field, asdict
from typing import Optional, List


@dataclass
class User:
    id: int
    name: str
    email: str
    role: str = "member"
    is_active: bool = True

    def to_dict(self) -> dict:
        return asdict(self)

    @classmethod
    def from_dict(cls, data: dict) -> "User":
        return cls(**{k: v for k, v in data.items() if k in cls.__dataclass_fields__})


# In-memory user store (simulates a database)
_users: dict[int, User] = {
    1: User(id=1, name="Alice", email="alice@example.com", role="admin"),
    2: User(id=2, name="Bob", email="bob@example.com", role="member"),
    3: User(id=3, name="Charlie", email="charlie@example.com", role="member", is_active=False),
}

_next_id = 4


def get_all_users() -> List[User]:
    """Return all active users."""
    return [u for u in _users.values() if u.is_active]


def get_user_by_id(user_id: int) -> Optional[User]:
    """Return a user by ID, or None if not found."""
    return _users.get(user_id)


def create_user(name: str, email: str, role: str = "member") -> User:
    """Create a new user and return it."""
    global _next_id
    user = User(id=_next_id, name=name, email=email, role=role)
    _users[_next_id] = user
    _next_id += 1
    return user


def delete_user(user_id: int) -> bool:
    """Soft-delete a user. Returns True if found and deleted."""
    user = _users.get(user_id)
    if user is None:
        return False
    user.is_active = False
    return True


def reset_store():
    """Reset the store to initial state (for testing)."""
    global _users, _next_id
    _users = {
        1: User(id=1, name="Alice", email="alice@example.com", role="admin"),
        2: User(id=2, name="Bob", email="bob@example.com", role="member"),
        3: User(id=3, name="Charlie", email="charlie@example.com", role="member", is_active=False),
    }
    _next_id = 4

