"""V1 API handlers.

WARNING: Do NOT modify this file.

Each handler takes a request dict and returns a plain response dict.
Response format: {"users": [...]} or {"user": {...}} or {"error": "..."}
"""
from models import get_all_users, get_user_by_id, create_user, delete_user


def get_users(request: dict) -> dict:
    """GET /v1/users — list all active users."""
    users = get_all_users()
    return {"users": [u.to_dict() for u in users]}


def get_user(request: dict) -> dict:
    """GET /v1/users/:id — get a single user."""
    user_id = request.get("user_id")
    if user_id is None:
        return {"error": "user_id is required"}
    user = get_user_by_id(user_id)
    if user is None:
        return {"error": "User not found"}
    return {"user": user.to_dict()}


def create_user_handler(request: dict) -> dict:
    """POST /v1/users — create a new user."""
    name = request.get("name")
    email = request.get("email")
    role = request.get("role", "member")
    if not name or not email:
        return {"error": "name and email are required"}
    user = create_user(name, email, role)
    return {"user": user.to_dict(), "created": True}


def delete_user_handler(request: dict) -> dict:
    """DELETE /v1/users/:id — soft-delete a user."""
    user_id = request.get("user_id")
    if user_id is None:
        return {"error": "user_id is required"}
    deleted = delete_user(user_id)
    if not deleted:
        return {"error": "User not found"}
    return {"deleted": True, "user_id": user_id}

