"""Tests for v1 API endpoints.

WARNING: Do NOT modify this file.
"""
import sys
import os
import pytest

sys.path.insert(0, os.path.dirname(os.path.dirname(os.path.abspath(__file__))))

from router import dispatch
from models import reset_store


@pytest.fixture(autouse=True)
def reset():
    """Reset user store before each test."""
    reset_store()


class TestV1GetUsers:
    """Test GET /v1/users."""

    def test_get_users_returns_list(self):
        response = dispatch("GET", "/v1/users", {})
        assert "users" in response
        assert isinstance(response["users"], list)

    def test_get_users_has_active_only(self):
        response = dispatch("GET", "/v1/users", {})
        # Charlie is inactive, so only Alice and Bob
        assert len(response["users"]) == 2
        names = {u["name"] for u in response["users"]}
        assert names == {"Alice", "Bob"}

    def test_get_users_has_timestamp(self):
        response = dispatch("GET", "/v1/users", {})
        assert "timestamp" in response
        assert isinstance(response["timestamp"], float)

    def test_get_users_has_server_info(self):
        response = dispatch("GET", "/v1/users", {})
        assert response["server"] == "myapp/1.0"


class TestV1GetUser:
    """Test GET /v1/users/:id."""

    def test_get_existing_user(self):
        response = dispatch("GET", "/v1/users/:id", {"user_id": 1})
        assert "user" in response
        assert response["user"]["name"] == "Alice"
        assert response["user"]["email"] == "alice@example.com"

    def test_get_nonexistent_user(self):
        response = dispatch("GET", "/v1/users/:id", {"user_id": 999})
        assert "error" in response

    def test_get_user_has_timestamp(self):
        response = dispatch("GET", "/v1/users/:id", {"user_id": 1})
        assert "timestamp" in response


class TestV1CreateUser:
    """Test POST /v1/users."""

    def test_create_user(self):
        response = dispatch("POST", "/v1/users", {
            "name": "Dave", "email": "dave@example.com"
        })
        assert "user" in response
        assert response["user"]["name"] == "Dave"
        assert response["created"] is True

    def test_create_user_missing_fields(self):
        response = dispatch("POST", "/v1/users", {"name": "NoEmail"})
